class Solution:
    def minimizeSum(self, nums):
        n = len(nums)
        best = None
        for i in range(n):
            for j in range(i + 1, n):
                rest = [nums[k] for k in range(n) if k != i and k != j]
                rng = max(rest) - min(rest) if rest else 0
                if best is None or rng < best:
                    best = rng
        return best

